    /// Shows an editor dropdown. In .NET 9 the parameter of
    /// IWindowsFormsEditorService.DropDownControl is now non-nullable,
    /// so callers must guard against null.
    /// </summary>
    public void ShowDropDown(IWindowsFormsEditorService editorService, Control? control)
    {
        if (control is not null)
        {
            editorService.DropDownControl(control);
        }
    }
}

